module.exports = {
  createProject(data) {
    return new Promise((resolve, reject) => {
      if (!data.name) return reject({ status: 400, message: 'Name is required' });
      const project = { id: generateId(), ...data, members: [] };
      projects.push(project);
      resolve(project);
    })
  },
  getProject(id) {
    return projects.find(p => p.id === id);
  },
  getTasks(id) {
    const project = this.getProject(id);
    if (!project) return [];
    return project.tasks || [];
  }
