const tasksService = require('./service');
router.post('/', (req, res) => {
  if (!req.body.status || req.body.status !== 'todo') return sendError(res, 400, 'InvalidInput', 'Status must be todo');
  tasksService.createTask(req.params.projectId, { status: 'todo' }).then((task) => {
    res.status(201).json({ task });
  }).catch((err) => sendError(res, err.status || 500, 'ServiceError', err.message));
});
