const tasks = [];
module.exports = {
  createTask(projectId, data) {
    return new Promise((resolve, reject) => {
      const project = projectsService.getProject(projectId);
      if (!project) return reject({ status: 404, message: 'Project not found' });
      const task = { id: generateId(), ...data };
      tasks.push(task);
      project.tasks = project.tasks || [];
      project.tasks.push(task);
      resolve(task);
    })
  },
  updateTask(projectId, taskId, data) {
    return new Promise((resolve, reject) => {
      const project = projectsService.getProject(projectId);
      if (!project) return reject({ status: 404, message: 'Project not found' });
      const taskIndex = project.tasks.findIndex(t => t.id === taskId);
      if (taskIndex === -1) return reject({ status: 404, message: 'Task not found' });
      project.tasks[taskIndex] = { ...project.tasks[taskIndex], ...data };
      resolve(project.tasks[taskIndex]);
    })
  }
};
